// Pull a country's real world-map bbox (from its symbol viewBox) + inner paths.
// The stored paths are in the SHARED @svg-maps/world coordinate space, so two
// countries drawn together land in their true relative positions automatically.
function parseCountry(slug: string): { x: number; y: number; w: number; h: number; inner: string } | null {
  const sym = COUNTRY_SYMBOLS[slug];
  if (!sym) return null;
  const vb = sym.match(/viewBox="([-\d.\s]+)"/i);
  if (!vb) return null;
  const [x, y, w, h] = vb[1].trim().split(/\s+/).map(Number);
  if ([x, y, w, h].some((n) => !Number.isFinite(n))) return null;
  const inner = sym.replace(/^<symbol\b[^>]*>/i, "").replace(/<\/symbol>\s*$/i, "");
  return { x, y, w, h, inner };
}

const r2 = (n: number) => Math.round(n * 100) / 100;

// Build ONE symbol that holds several countries at their TRUE relative positions
// and sizes — viewBox = the union of their real bounding boxes. Rendered via a
// single <use>, the countries keep accurate geography and CANNOT overlap.
function buildCombinedMap(slugs: string[]): { id: string; symbol: string } | null {
  const parts = slugs
    .map((s) => ({ slug: s, p: parseCountry(s) }))
    .filter((e): e is { slug: string; p: NonNullable<ReturnType<typeof parseCountry>> } => e.p !== null);
  if (!parts.length) return null;
  const minX = Math.min(...parts.map((e) => e.p.x));
  const minY = Math.min(...parts.map((e) => e.p.y));
  const maxX = Math.max(...parts.map((e) => e.p.x + e.p.w));
  const maxY = Math.max(...parts.map((e) => e.p.y + e.p.h));
  const id = "mm-apac-" + parts.map((e) => e.slug).sort().join("-");
  const inner = parts.map((e) => e.p.inner).join("");
  return {
    id,
    symbol: `<symbol id="${id}" viewBox="${r2(minX)} ${r2(minY)} ${r2(maxX - minX)} ${r2(maxY - minY)}">${inner}</symbol>`,
  };
}

export function injectCountryKit(svg: string): string {
  if (svg.includes('id="mm-countries"')) return svg;
  const defs: string[] = [];
  const added = new Set<string>();

  // Combined maps: <use href="#mm-apac-map" data-countries="a,b,c" …>. Each is
  // rewritten to a unique combined symbol holding those countries in true
  // geography. An empty/missing list defaults to the whole APAC footprint.
  let out = svg.replace(/<use\b[^>]*?href="#mm-apac-map"[^>]*?\/?>/gi, (tag) => {
    const dc = tag.match(/data-countries="([^"]*)"/i);
    let slugs = (dc ? dc[1] : "")
      .split(/[,\s]+/)
      .map((s) => s.trim().toLowerCase())
      .filter((s) => COUNTRY_SYMBOLS[s]);
    if (!slugs.length) slugs = Object.keys(COUNTRY_SYMBOLS);
    const combined = buildCombinedMap([...new Set(slugs)]);
    if (!combined) return tag;
    if (!added.has(combined.id)) {
      defs.push(combined.symbol);
      added.add(combined.id);
    }
    return tag
      .replace(/href="#mm-apac-map"/i, `href="#${combined.id}"`)
      .replace(/\s*data-countries="[^"]*"/i, "");
  });

  // Single-country motifs referenced directly (one country can't overlap itself).
  for (const m of out.matchAll(/href="#mm-map-([a-z]+)"/g)) {
    const id = "mm-map-" + m[1];
    if (COUNTRY_SYMBOLS[m[1]] && !added.has(id)) {
      defs.push(COUNTRY_SYMBOLS[m[1]]);
      added.add(id);
    }
  }

  if (!defs.length) return out;
  return out.replace(/(<svg\b[^>]*>)/i, `$1<defs id="mm-countries">${defs.join("")}</defs>`);
}

export const COUNTRY_KIT_DOC = "━━ COUNTRY SHAPES (real geographic outlines) ━━\\nIf a slide depicts Mad Monkey's countries or any map, you MUST use these real outlines — NEVER freehand or approximate a country shape.\\n\\nONE country (a single-country motif): <use href=\"#mm-map-<country>\" x=\"…\" y=\"…\" width=\"…\" height=\"…\" color=\"#hex\"/> — fills the box keeping true proportions.\\n\\nTWO OR MORE countries / any region map: use ONE element — NEVER place several #mm-map-<country> yourself; placed separately they OVERLAP and land in the wrong geographic positions. Instead:\\n<use href=\"#mm-apac-map\" data-countries=\"indonesia,philippines,australia\" x=\"…\" y=\"…\" width=\"…\" height=\"…\" color=\"#hex\"/>\\nList the countries you want (comma-separated slugs) in data-countries. They render in their TRUE relative positions and sizes — real geography, accurate spacing, and they CAN NEVER overlap (e.g. the Philippines sits north, Indonesia along the equator, Australia far to the south-east). The whole set scales together to fit your width×height box and auto-fits without distortion, so the box can be any size. Colour applies to the whole map (one fill).\\nOmit data-countries (or leave it empty) to draw the FULL Mad Monkey APAC footprint (all 9 countries) accurately.\\n\\nAvailable slugs: indonesia, cambodia, thailand, philippines, vietnam, laos, malaysia, myanmar, australia. These are the ONLY countries — for anywhere else use labelled pins, a list, or a bank photo; never invent a shape.\\n\\nExample (our APAC footprint, ~720px wide, cyan): <use href=\"#mm-apac-map\" data-countries=\"thailand,cambodia,vietnam,laos,myanmar,malaysia,indonesia,philippines,australia\" x=\"160\" y=\"170\" width=\"720\" height=\"520\" color=\"#00fef3\"/>";
